head.script:
scwin.rowIndex;

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSZZ1100000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 로그인한 사용자 ID 변수설정
	scwin.usrId = comLib.getUsrId();

	// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
	scwin.setAthrSysDivCd();
};

/**
 * 사용자에게 부여가된 권한의 시스템구분코드만을 조회
 * @param
 * @return
 */
scwin.setAthrSysDivCd = function() {
	var requestData = {};
	requestData.data = {"usrId" : scwin.usrId, "sysDivCd" : "SCM_0000"};

	var option = {
		action : "sc/authmng/retrieveAthrSysDivCd.do",
		reqData : requestData,
		resData : dltSysDivCdList,
		success : "scwin.retrieveAthrSysDivCdCallback",
		isShowMeg : false
	};
	ajaxLib.requestAjaxSyncCode($p, option);
};

/**
 * 조회 CallBack 실행
 * @param <Object> resBody
 * @return
 */
scwin.retrieveAthrSysDivCdCallback = function(resBody, e) {
	if (dltSysDivCdList.getRowCount() == 0) {
		// 시스템관리자만 접근이 가능합니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
		return;
	}

	var sysDivCd = comLib.getSysDivCd();

	dmaInqireParam.set("intnSysDivCd", sysDivCd);
	dmaInqireParam.set("usrId", scwin.usrId);

	// 화면 오픈시 자동조회를 한다. 
	comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire_onclick);
	scwin.btnInqire_onclick();
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var requestData = {};
	requestData.dmaInqireParam = dmaInqireParam.getJSON();

	var option = {
		action : "zz/authmng/retrieveScrinBtn.do",
		reqData : requestData,
		resData : dltScrinBtnList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.inqireCallback = function(resBody) {
	if (resBody.message.code == "success") {
		txtCnt.setValue(dltScrinBtnList.getRowCount());

		// 조회된 값에 권한ID가 비어있지 않으면 읽기 속성으로 비어 있으면 쓰기 로 설정 변경 
		for (var idx = 0; idx < dltScrinBtnList.getRowCount(); idx++) {
			if (idx < 7) {
				grdScrinBtnList.setRowReadOnly(idx, true);
			} else {
				grdScrinBtnList.setCellReadOnly(idx, "btnSeq", true);
			}
		}
	} else {
		comLib.alert($p, "fail");
	}
};

/**
 * 버튼권한 행 추가
 * @param
 * @return
 */
scwin.btnAddRow_onclick = function() {
	var rowIndex = dltScrinBtnList.insertRow();

	dltScrinBtnList.setCellData(rowIndex, "intnSysDivCd", comLib.getSysDivCd());
	dltScrinBtnList.setCellData(rowIndex, "btnSeq", dltScrinBtnList.getRowCount());
	grdScrinBtnList.setFocusedCell(rowIndex, "btnNm", true);
};

/**
 * 버튼권한 행 삭제
 * @param
 * @return
 */
scwin.btnDelRow_onclick = function() {
	var rowIndex = grdScrinBtnList.getFocusedRowIndex();
	var rowStatus = dltScrinBtnList.getRowStatus(rowIndex);

	if (rowStatus != "C") {
		// 행 삭제 시 기존건이면 조회 후 삭제 요청
		var btnSeq = dltScrinBtnList.getCellData(rowIndex , "btnSeq");

		if (btnSeq != null || btnSeq != "") {
			dmaSaveScrinBtn.setJSON(dltScrinBtnList.getRowJSON(rowIndex));
			scwin.inqireScrinBtnUse(rowIndex);
		} else {
			// 삭제하고자 하는 데이터 선택 후 삭제하도록 알림
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00252"));
		}
	} else {
		// 행 삭제 시 신규건이면 그리드에서 바로 삭제
		dltScrinBtnList.removeRow(rowIndex);
	}
};

/**
 * 버튼권한 삭제전 등록된 정보가 있는지 확인한다.
 * @param
 * @return
 */
scwin.inqireScrinBtnUse = function(rowIndex) {
	var requestData = {};
	requestData.dmaSaveScrinBtn = dmaSaveScrinBtn.getJSON();

	scwin.rowIndex = rowIndex;

	var option = {
		action : "zz/authmng/selectScrinBtnUse.do",
		reqData : requestData,
		resData : dmaInqireScrinBtn,
		success : "scwin.inqireScrinBtnUseCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 화면 삭제전 등록된 정보조회 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.inqireScrinBtnUseCallback = function(resBody) {
	var menuCnt = 0;
	var usrCnt = 0;

	if (resBody.message.code == "success") {
		menuCnt = dmaInqireScrinBtn.get("menuCnt");
		usrCnt = dmaInqireScrinBtn.get("usrCnt");

		// 사용하는 곳이 없으면 삭제 요청한다.
		if (menuCnt == 0 && usrCnt == 0) {
			dltScrinBtnList.deleteRow(scwin.rowIndex);
			// scwin.btnSave_onclick();
		} else {
			// 사용중인 데이터는 삭제 못하도록 메세지 알림
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00246", dmaInqireScrinBtn.get("btnNm")));
		}
	}
};

/**
 * 메뉴상세에서 기재한 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	var valInfo = [
		{id : "btnSeq", mandatory : true, number : true},
		{id : "btnNm", mandatory : true},
		{id : "btnAthrVu", mandatory : true}
	];

	if (dltScrinBtnList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	if (utilLib.validateGridView(grdScrinBtnList, valInfo)) {
		// 변경된 내역이 있습니다.\n저장 하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00239"), "scwin.saveConfirmCallback");
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	requestData.dltScrinBtnList = dltScrinBtnList.getModifiedJSON();

	var option = {
		action : "zz/authmng/saveScrinBtn.do",
		reqData : requestData,
		success : "scwin.saveScrinBtnCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveScrinBtnCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	dmaInqireParam.reset();
	dltScrinBtnList.removeAll();

	scwin.btnInqire_onclick();
};

/**
 * 화면목록에서 선택한 버튼권한을 삭제한다.
 * @param
 * @return
 */
scwin.btnDel_onclick = function() {
	if (dltScrinBtnList.getModifiedData() != "") {
		comLib.removeGridView(grdScrinBtnList);

		// 삭제하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
	} else {
		// 삭제할 자료를 선택한 후 처리하시기 바랍니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00252"));
	}
};
